如果你只需要第一条映射（不关心 `/mcp1/xxx`），可以只保留 `location = /mcp1`。

可以，把 `/mcp1/` 这个前缀“剥掉”，其余路径原样转发到上游根路径即可：

```nginx
upstream mcp1 {
    server 100.103.21.152:8095;
}

server {
    listen 10000;

    # /mcp1 统一跳到 /mcp1/
    location = /mcp1 {
        return 301 /mcp1/;
    }

    # /mcp1/xxx  ->  /xxx
    location ^~ /mcp1/ {
        proxy_pass http://mcp1/;   # 关键：这里必须以 / 结尾，才能做前缀替换
